import React, { useState } from 'react';
import { Button } from 'react-bootstrap';
import Form from 'react-bootstrap/Form';
import { NavLink } from 'react-router-dom';
import "./Login.css"

export const Login = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');

    const handleLogin = async (ev: React.FormEvent) => {
        ev.preventDefault();
        const isAuthenticated = await fetch('http://localhost:4000/login', {
            method: 'POST',
            body: JSON.stringify({username, password}),
            headers: {'Content-Type': 'application/json'},
        });
    } 



    return (
        // <div className="content">
        //     <form action="login">
        //         <input type="text" placeholder="Username"></input>
        //         <input type="text" placeholder="Password"></input>
        //         <button type="button">Login</button>
        //     </form>
        // </div>


        <div className="content">
            <div className="container">
                <div className="row">
                    <div className="col-md-6 offset-md-3">
                        <div className="card">
                            <div className="card-body">
                                <h3 className="card-title text-center">Login</h3>
                                    <form onSubmit={handleLogin()}>
                                        <div className="mb-3">
                                            <label htmlFor="email" className="form-label">Email</label>
                                            <input type="email" className="form-control" 
                                                id="email" placeholder="Enter your email" 
                                                value={username}
                                                onChange={ev => setUsername(ev.target.value)}/>
                                        </div>
                                        <div className="mb-3">
                                            <label htmlFor="password" className="form-label">Password</label>
                                            <input type="password" className="form-control" 
                                                id="password" placeholder="Enter your password" 
                                                value={password}
                                                onChange={ev => setPassword(ev.target.value)}/>
                                        </div>
                                        <div className="register-container">
                                            <button type="submit" className="btn btn-primary btn-block">Login</button>
                                            <NavLink to="/register" className='register'>Register</NavLink>
                                        </div>
                                    </form>
                                </div>
                        </div>
                    </div>
                </div>
            </div>
      </div>
  //need all these divs to pretty up the login page, container, row, col, card are all bootstrap classes
    )
}
